import java.util.*;

public class Solution {
    public static long solve(long[][] points) {
        int n = points.length;
        Map<String, Map<Long, Integer>> slopeGroupMap = new HashMap<>();
        Map<String, Integer> midPointCount = new HashMap<>();

        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                long x1 = points[i][0], y1 = points[i][1];
                long x2 = points[j][0], y2 = points[j][1];
                long dx0 = x2 - x1;
                long dy0 = y2 - y1;

                long adx = Math.abs(dx0);
                long ady = Math.abs(dy0);
                long g = gcd(adx, ady);
                if (g == 0) g = 1;
                long dx = dx0 / g;
                long dy = dy0 / g;

                if (dx < 0 || (dx == 0 && dy < 0)) {
                    dx = -dx;
                    dy = -dy;
                }

                String slopeKey = dx + "," + dy;
                long interceptKey;
                if (dx == 0 && dy == 0) {
                    continue;
                } else if (dx == 0) {
                    interceptKey = x1;
                } else {
                    interceptKey = dy * x1 - dx * y1;
                }

                Map<Long, Integer> innerMap = slopeGroupMap.computeIfAbsent(slopeKey, k -> new HashMap<>());
                innerMap.put(interceptKey, innerMap.getOrDefault(interceptKey, 0) + 1);

                long midx = x1 + x2;
                long midy = y1 + y2;
                String midKey = midx + "," + midy;
                midPointCount.put(midKey, midPointCount.getOrDefault(midKey, 0) + 1);
            }
        }

        long totalT1 = 0;
        for (Map<Long, Integer> innerMap : slopeGroupMap.values()) {
            long total = 0;
            for (int count : innerMap.values()) {
                total += count;
            }
            if (total < 2) continue;
            long allPairs = total * (total - 1) / 2;
            long innerPairs = 0;
            for (int count : innerMap.values()) {
                if (count >= 2) {
                    innerPairs += (long) count * (count - 1) / 2;
                }
            }
            totalT1 += (allPairs - innerPairs);
        }

        long totalT2 = 0;
        for (int count : midPointCount.values()) {
            if (count >= 2) {
                totalT2 += (long) count * (count - 1) / 2;
            }
        }

        return totalT1 - totalT2;
    }

    private static long gcd(long a, long b) {
        if (b == 0) return a;
        return gcd(b, a % b);
    }
}
