import java.util.*;

public class TrapezoidCount {
    private static long gcd(long a, long b) {
        if (b == 0)
            return Math.abs(a);
        return gcd(b, Math.abs(a) % Math.abs(b));
    }

    private static long[] normalize(long dx, long dy) {
        if (dx == 0 && dy == 0) {
            return new long[]{0, 0};
        }
        if (dx == 0) {
            return new long[]{0, 1};
        }
        if (dy == 0) {
            return new long[]{1, 0};
        }
        long g = gcd(dx, dy);
        dx /= g;
        dy /= g;
        if (dx < 0 || (dx == 0 && dy < 0)) {
            dx = -dx;
            dy = -dy;
        }
        return new long[]{dx, dy};
    }

    public static long solve(long[][] points) {
        int n = points.length;
        Map<String, List<int[]>> slopeGroupMap = new HashMap<>();
        Map<String, Map<Long, List<int[]>>> slopeLenGroupMap = new HashMap<>();

        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                long dx = points[j][0] - points[i][0];
                long dy = points[j][1] - points[i][1];
                long[] slope = normalize(dx, dy);
                String slopeKey = slope[0] + "," + slope[1];
                long lenSq = dx * dx + dy * dy;

                List<int[]> slopeGroup = slopeGroupMap.computeIfAbsent(slopeKey, k -> new ArrayList<>());
                slopeGroup.add(new int[]{i, j});

                Map<Long, List<int[]>> innerMap = slopeLenGroupMap.computeIfAbsent(slopeKey, k -> new HashMap<>());
                List<int[]> lenGroup = innerMap.computeIfAbsent(lenSq, k -> new ArrayList<>());
                lenGroup.add(new int[]{i, j});
            }
        }

        long totalTrapezoids = 0;
        for (List<int[]> group : slopeGroupMap.values()) {
            int groupSize = group.size();
            long totalPairs = (long) groupSize * (groupSize - 1) / 2;
            Map<Integer, Integer> degrees = new HashMap<>();
            for (int[] seg : group) {
                int u = seg[0], v = seg[1];
                degrees.put(u, degrees.getOrDefault(u, 0) + 1);
                degrees.put(v, degrees.getOrDefault(v, 0) + 1);
            }
            long nonDisjoint = 0;
            for (int deg : degrees.values()) {
                nonDisjoint += (long) deg * (deg - 1) / 2;
            }
            long disjointPairs = totalPairs - nonDisjoint;
            totalTrapezoids += disjointPairs;
        }

        long totalParaEvents = 0;
        for (Map<Long, List<int[]>> innerMap : slopeLenGroupMap.values()) {
            for (List<int[]> group : innerMap.values()) {
                int groupSize = group.size();
                if (groupSize < 2) continue;
                for (int i = 0; i < groupSize; i++) {
                    int[] seg1 = group.get(i);
                    int a = seg1[0], b = seg1[1];
                    long[] pA = points[a], pB = points[b];
                    for (int j = i + 1; j < groupSize; j++) {
                        int[] seg2 = group.get(j);
                        int c = seg2[0], d = seg2[1];
                        if (a == c || a == d || b == c || b == d) continue;
                        long[] pC = points[c], pD = points[d];
                        boolean cond1 = (pA[0] + pD[0] == pB[0] + pC[0]) && (pA[1] + pD[1] == pB[1] + pC[1]);
                        boolean cond2 = (pA[0] + pC[0] == pB[0] + pD[0]) && (pA[1] + pC[1] == pB[1] + pD[1]);
                        if (cond1 || cond2) {
                            totalParaEvents++;
                        }
                    }
                }
            }
        }

        long uniqueParas = totalParaEvents / 2;
        return totalTrapezoids - uniqueParas;
    }
}
